mapper.select:
SELECT * FROM ( SELECT 'LIKE' AS actionType, l.user_id AS actorId, COALESCE(up.nickname, u.nickname, u.username) AS actorName, COALESCE(up.avatar, u.avatar) AS actorAvatar, a.id AS articleId, a.title AS articleTitle, l.create_time AS eventTime FROM article_like l INNER JOIN article a ON a.id = l.article_id LEFT JOIN user_profile up ON up.user_id = l.user_id LEFT JOIN user u ON u.id = l.user_id WHERE a.author_id = #{userId}
UNION ALL
SELECT 'FAVORITE' AS actionType, f.user_id AS actorId, COALESCE(up.nickname, u.nickname, u.username) AS actorName, COALESCE(up.avatar, u.avatar) AS actorAvatar, a.id AS articleId, a.title AS articleTitle, f.create_time AS eventTime FROM article_favorite f INNER JOIN article a ON a.id = f.article_id LEFT JOIN user_profile up ON up.user_id = f.user_id LEFT JOIN user u ON u.id = f.user_id WHERE a.author_id = #{userId}
UNION ALL
SELECT 'COMMENT' AS actionType, c.user_id AS actorId, COALESCE(up.nickname, u.nickname, u.username, c.author) AS actorName, COALESCE(up.avatar, u.avatar) AS actorAvatar, a.id AS articleId, a.title AS articleTitle, c.create_time AS eventTime FROM comment c INNER JOIN article a ON a.id = c.article_id LEFT JOIN user_profile up ON up.user_id = c.user_id LEFT JOIN user u ON u.id = c.user_id WHERE a.author_id = #{userId} AND c.status = 1 AND (c.user_id IS NULL OR c.user_id != #{userId})
UNION ALL
SELECT 'FOLLOW' AS actionType, uf.follower_id AS actorId, COALESCE(up.nickname, u.nickname, u.username) AS actorName, COALESCE(up.avatar, u.avatar) AS actorAvatar, NULL AS articleId, NULL AS articleTitle, uf.create_time AS eventTime FROM user_follow uf LEFT JOIN user_profile up ON up.user_id = uf.follower_id LEFT JOIN user u ON u.id = uf.follower_id WHERE uf.followee_id = #{userId} ) t ORDER BY t.eventTime DESC LIMIT #{limit}
